import { NComponent, defineComponent, NCTable, TableColumn } from "@ncom/all";

import { genData, genColumns } from "../data/tabledata";

export default class Table9 extends NComponent {
  constructor() {
    super();
  }
  template() {
    return `
      <nc-table keyName='id' items={this.genColumns()} style='height:300px' row-alt>
        <nc-pagination total={500} @nc-change={this.changePage} pageSize={30}></nc-pagination>
      </nc-table>
    `;
  }

  genColumns(): TableColumn[] {
    return genColumns();
  }

  changePage(e: CustomEvent<{ pageNo: number; pageSize: number }>) {
    //可通过detail的pageNo和pageSize从服务器获取数据
    //此处直接生成数据
    ((e.target as HTMLElement).parentElement as NCTable).setRecords(genData(e.detail.pageSize, (e.detail.pageNo - 1) * e.detail.pageSize));
  }
}

defineComponent("nc-table-ex9", Table9);
